var e=[{id:`L2_1`,type:`dialog`,speaker:`LENA_COFFIN_NULL_NULL`,text:{KOREA:`지금부터 홀로그램 시뮬레이터를 이용한 전선확보용 모의전 브리핑을 시작하겠습니다.`,JPN:`今からホログラムシミュレーターを利用した電線確保用模擬戦ブリーフィングを始めます。`,ENG:`We will now begin the mock battle briefing for securing the front by using a hologram simulator.`,TWN:`現在，我們將使用模擬全息影像開始進行前線模擬戰的彙報。`},stage:{bg:`WORKSHOP`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LENA_COFFIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`LENA_COFFIN_NULL_NULL`,text:{KOREA:`알트 소대는 이번 다이브 작전이 처음일 테니 잘 들어 주세요.`,JPN:`アルト小隊は今回ダイブ作戦が初めてのつもりであるからよく聞き入れてください。`,ENG:`ALT Squad, since this is your first Dive mission, please listen carefully.`,TWN:`阿爾特小隊，這是你們第一次進行躍入作戰，所以仔細聽好了。`},stage:{bg:`WORKSHOP`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LENA_COFFIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`SEOYOON_ALT_NULL_NULL`,text:{KOREA:`네, 잘 부탁드립니다.`,JPN:`はい、よろしくお願いいたします。`,ENG:`Yes, I look forward to it.`,TWN:`好的，請多多指教。`},stage:{bg:`WORKSHOP`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SEOYOON_ALT_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`LENA_COFFIN_NULL_NULL`,text:{KOREA:`어...... 그런데 서윤 소대장님, 다른 팀원 분들은 어디 있죠?`,JPN:`語......ところでソニア小隊長様、他のチームメンバー方々はどこにあります?`,ENG:`Uh... But Commander Seo Yoon, where are you team members?`,TWN:`呃……話說徐芸隊長，你們其他隊員在哪？`},stage:{bg:`WORKSHOP`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LENA_COFFIN_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`SEOYOON_ALT_NULL_NULL`,text:{KOREA:`아하하, 두 사람 사이에 사소한 갈등이 생겨서 한 명이 중재를 하는 중이에요.`,JPN:`アハハ、二人の間にささいな葛藤が生じて一人が仲裁をする中です。`,ENG:`Ah hah hah, there was a slight dispute between two of the members, so the one other member is trying to sort things out.`,TWN:`啊哈哈，因為有兩個人發生了點小衝突，然後有一個人在勸架。`},stage:{bg:`WORKSHOP`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SEOYOON_ALT_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`LENA_COFFIN_NULL_NULL`,text:{KOREA:`흠, 알겠습니다. 일단은 시간이 없으니 이대로 진행할게요.`,JPN:`傷、わかりました。一応時間がないからこのまま進行しますよ。`,ENG:`Hmm, very well. We will proceed, since we don't have a lot of time.`,TWN:`呃，好吧。因為時間有限，我就先繼續吧。`},stage:{bg:`WORKSHOP`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LENA_COFFIN_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}}];export{e as default};